using Microsoft.Build.Logging.StructuredLogger;

var binlogPath = args.Length > 0 ? args[0] : "build.binlog";
var build = BinaryLog.ReadBuild(binlogPath);

Console.WriteLine($"Build Succeeded: {build.Succeeded}");
Console.WriteLine();

// Collect all errors
var errors = new List<(string Project, string Code, string File, int Line, string Message)>();

build.VisitAllChildren<Error>(error =>
{
    var project = "";
    var node = error.Parent;
    while (node != null)
    {
        if (node is Project p)
        {
            project = System.IO.Path.GetFileName(p.ProjectFile ?? "");
            break;
        }
        node = node.Parent;
    }
    errors.Add((project, error.Code ?? "", error.File ?? "", error.LineNumber, error.Text ?? error.ToString()));
});

// Group errors by project
var byProject = errors.GroupBy(e => e.Project).OrderBy(g => g.Key);

Console.WriteLine($"=== Total Errors: {errors.Count} ===");
Console.WriteLine();

foreach (var group in byProject)
{
    Console.WriteLine($"--- Project: {group.Key} ({group.Count()} errors) ---");
    foreach (var e in group)
    {
        var location = string.IsNullOrEmpty(e.File) ? "" : $" [{System.IO.Path.GetFileName(e.File)}:{e.Line}]";
        Console.WriteLine($"  {e.Code}{location}: {e.Message}");
    }
    Console.WriteLine();
}

// Also show warnings that might be relevant
var warnings = new List<(string Project, string Code, string Message)>();
build.VisitAllChildren<Warning>(warning =>
{
    var project = "";
    var node = warning.Parent;
    while (node != null)
    {
        if (node is Project p)
        {
            project = System.IO.Path.GetFileName(p.ProjectFile ?? "");
            break;
        }
        node = node.Parent;
    }
    warnings.Add((project, warning.Code ?? "", warning.Text ?? warning.ToString()));
});

if (warnings.Any())
{
    Console.WriteLine($"=== Total Warnings: {warnings.Count} ===");
    foreach (var w in warnings.GroupBy(w => w.Project))
    {
        Console.WriteLine($"--- Project: {w.Key} ---");
        foreach (var warning in w)
        {
            Console.WriteLine($"  {warning.Code}: {warning.Message}");
        }
    }
}

// Show project dependency information
Console.WriteLine();
Console.WriteLine("=== Project References ===");
build.VisitAllChildren<Project>(project =>
{
    var refs = new List<string>();
    project.VisitAllChildren<Item>(item =>
    {
        if (item.Name == "ProjectReference")
        {
            refs.Add(System.IO.Path.GetFileName(item.Text));
        }
    });
    if (refs.Any())
    {
        Console.WriteLine($"  {System.IO.Path.GetFileName(project.ProjectFile ?? "")} -> {string.Join(", ", refs.Distinct())}");
    }
});
